module top_module (
    input clk,
    input sreset,
    output [2:0] q );reg [2:0] counter_value;

    always @(posedge clk) begin
        if (sreset)
            counter_value <= 3'b000;
        else
            counter_value <= counter_value + 1;
    end

    assign q = counter_value;

endmodule
